code:
def divide(a,b):
    if b==0:
        return None
    return a/b

def factorial(n):
    if n==0:
        return 1
    return n*factorial(n-1)

def sum_list(nums):
    total = 0
    for n in nums:
        total += n
    return total

def find_max(values):
    max_val = values[0]
    for v in values:
        if v > max_val:
            max_val = v
    return max_val

def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n-1)

def filter_even(nums):
    result = []
    for n in nums:
        if n % 2 == 0:
            result.append(n)
    return result

def safe_divide(a,b):
    if b == 0:
        return None
    return a / b

def average(nums):
    if not nums:
        return 0
    return sum(nums) / len(nums)

def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n-1) + fibonacci(n-2)

def get_unique(items):
    seen = set()
    for item in items:
        seen.add(item)
    return list(seen)

def flatten(list_of_lists):
    result = []
    for sub in list_of_lists:
        for item in sub:
            result.append(item)
    return result

def count_occurrences(lst,val):
    count = 0
    for item in lst:
        if item == val:
            count += 1
    return count
